func TestE2E_AuditLogCreation(t *testing.T) {
    tmpDir := t.TempDir()

    // Initialize NTM with audit logging
    cmd := exec.Command("ntm", "init",
        "--project-dir", tmpDir,
        "--audit-log", filepath.Join(tmpDir, "audit.log"),
    )
    require.NoError(t, cmd.Run())

    // Perform auditable actions
    exec.Command("ntm", "spawn",
        "--project-dir", tmpDir,
        "--task", "Test task",
        "--dry-run",
    ).Run()

    // Verify audit log exists and has entries
    logPath := filepath.Join(tmpDir, "audit.log")
    data, err := os.ReadFile(logPath)
    require.NoError(t, err)
    require.NotEmpty(t, data)

    // Parse and verify entry structure
    var entry map[string]interface{}
    lines := strings.Split(strings.TrimSpace(string(data)), "\n")
    require.NoError(t, json.Unmarshal([]byte(lines[0]), &entry))

    assert.NotEmpty(t, entry["id"])
    assert.NotEmpty(t, entry["event"])
    assert.NotEmpty(t, entry["timestamp"])

    t.Logf("Audit log has %d entries", len(lines))
    t.Logf("First entry: %s", lines[0])
}
```

