func TestE2E_AuditQuery(t *testing.T) {
    tmpDir := t.TempDir()
    auditPath := filepath.Join(tmpDir, "audit.log")

    // Setup: Create some audit entries
    exec.Command("ntm", "--audit-log", auditPath, "spawn", "--task", "Task 1", "--dry-run").Run()
    time.Sleep(100 * time.Millisecond)
    exec.Command("ntm", "--audit-log", auditPath, "spawn", "--task", "Task 2", "--dry-run").Run()
    time.Sleep(100 * time.Millisecond)
    exec.Command("ntm", "--audit-log", auditPath, "kill", "cc_1", "--dry-run").Run()

    // Query all
    output, err := exec.Command("ntm", "audit", "query",
        "--log", auditPath,
        "--format", "json",
    ).CombinedOutput()
    require.NoError(t, err)

    var entries []map[string]interface{}
    require.NoError(t, json.Unmarshal(output, &entries))
    assert.GreaterOrEqual(t, len(entries), 3)

    // Query by event type
    output2, _ := exec.Command("ntm", "audit", "query",
        "--log", auditPath,
        "--event", "agent.spawned",
        "--format", "json",
    ).CombinedOutput()

    var spawnEntries []map[string]interface{}
    json.Unmarshal(output2, &spawnEntries)
    assert.Equal(t, 2, len(spawnEntries))

    t.Logf("Total entries: %d, spawn entries: %d", len(entries), len(spawnEntries))
}
```

