func TestE2E_AuditExport(t *testing.T) {
    tmpDir := t.TempDir()
    auditPath := filepath.Join(tmpDir, "audit.log")
    exportPath := filepath.Join(tmpDir, "export.csv")

    // Generate some entries
    for i := 0; i < 10; i++ {
        exec.Command("ntm", "--audit-log", auditPath,
            "spawn", "--task", fmt.Sprintf("Task %d", i), "--dry-run").Run()
    }

    // Export to CSV
