        "--log", auditPath,
        "--format", "csv",
        "--output", exportPath,
    ).CombinedOutput()
    require.NoError(t, err, "output: %s", output)

    // Verify CSV
    data, err := os.ReadFile(exportPath)
    require.NoError(t, err)

    lines := strings.Split(strings.TrimSpace(string(data)), "\n")
    assert.GreaterOrEqual(t, len(lines), 11) // Header + 10 entries
