func TestE2E_AuditVerification(t *testing.T) {
    tmpDir := t.TempDir()
    auditPath := filepath.Join(tmpDir, "audit.log")

    // Generate chained entries
    for i := 0; i < 5; i++ {
        exec.Command("ntm", "--audit-log", auditPath,
            "spawn", "--task", fmt.Sprintf("Task %d", i), "--dry-run").Run()
    }

    // Verify integrity
    output, err := exec.Command("ntm", "audit", "verify",
        "--log", auditPath,
    ).CombinedOutput()
    require.NoError(t, err)
    require.Contains(t, string(output), "Integrity verified")

    // Tamper with log
    data, _ := os.ReadFile(auditPath)
    lines := strings.Split(string(data), "\n")
    lines[2] = strings.Replace(lines[2], "agent.spawned", "tampered", 1)
    os.WriteFile(auditPath, []byte(strings.Join(lines, "\n")), 0644)

    // Verify should fail
    output2, err := exec.Command("ntm", "audit", "verify",
        "--log", auditPath,
    ).CombinedOutput()
    assert.Error(t, err)
    assert.Contains(t, string(output2), "Integrity check failed")

    t.Logf("Verification output (tampered): %s", output2)
}
```

