func TestE2E_AuditRetention(t *testing.T) {
    tmpDir := t.TempDir()
    auditPath := filepath.Join(tmpDir, "audit.log")

    // Generate old entries (mock timestamps)
    for i := 0; i < 20; i++ {
        exec.Command("ntm", "--audit-log", auditPath,
            "spawn", "--task", fmt.Sprintf("Task %d", i), "--dry-run").Run()
    }

    // Apply retention policy (keep last 7 days)
    output, err := exec.Command("ntm", "audit", "prune",
        "--log", auditPath,
        "--retention", "7d",
        "--archive", filepath.Join(tmpDir, "archive"),
    ).CombinedOutput()
    require.NoError(t, err, "output: %s", output)

    // Verify old entries archived
    archiveFiles, _ := filepath.Glob(filepath.Join(tmpDir, "archive", "*.log.gz"))
    t.Logf("Archive files created: %v", archiveFiles)
}
